// 直接传 shadow 内 HTMLElement;内部 canvas 因而落在 shadow 容器
import { LuckyWheel, LuckyGrid, SlotMachine } from 'https://cdn.jsdelivr.net/npm/lucky-canvas@1/+esm';
const el = document.createElement('div'); shadowRoot.appendChild(el);
const { variant = 'wheel', ...config } = data;
const Ctor = { wheel: LuckyWheel, grid: LuckyGrid, slot: SlotMachine }[variant];
const lucky = new Ctor(el, { width: '400px', height: '400px', ...config });
